import React, { useState } from "react";
import { parseHTMLFile } from "./utils/htmlParser";

export default function App() {
  const [program, setProgram] = useState(null);
  const [error, setError] = useState("");

  const handleFile = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setError("");

    try {
      const data = await parseHTMLFile(file);
      console.log("Programme parsé :", data);
      setProgram(data);
    } catch (err) {
      console.error(err);
      setError("Erreur lors du parsing du fichier HTML.");
    }
  };

  return (
    <div
      style={{
        padding: 20,
        background: "#111",
        color: "white",
        minHeight: "100vh",
        fontFamily: "Arial, sans-serif",
      }}
    >
      <h1>FitCoach</h1>
      <p>Importe ton fichier HTML de programme.</p>

      <input type="file" accept=".html,.htm" onChange={handleFile} />

      {error && (
        <p style={{ color: "tomato", marginTop: 16 }}>
          {error}
        </p>
      )}

      {program && (
        <div style={{ marginTop: 24 }}>
          <h2>{program.programName || "Programme"}</h2>
          {program.clientName && <p>Client : {program.clientName}</p>}

          {program.weeks?.map((week) => (
            <div
              key={week.weekNumber}
              style={{
                marginTop: 20,
                padding: 16,
                border: "1px solid #333",
                borderRadius: 8,
              }}
            >
              <h3>Semaine {week.weekNumber}</h3>

              {week.sessions?.map((session, i) => (
                <div
                  key={i}
                  style={{
                    marginTop: 16,
                    padding: 12,
                    background: "#1b1b1b",
                    borderRadius: 8,
                  }}
                >
                  <h4>{session.name}</h4>

                  {session.description && (
                    <p style={{ color: "#bbb" }}>{session.description}</p>
                  )}

                  {session.exercises?.length > 0 ? (
                    <div style={{ marginTop: 12 }}>
                      {session.exercises.map((ex, j) => (
                        <div
                          key={j}
                          style={{
                            padding: 10,
                            marginBottom: 10,
                            background: "#222",
                            borderRadius: 6,
                          }}
                        >
                          <strong>{ex.name}</strong>
                          <div style={{ marginTop: 6, color: "#ccc" }}>
                            <div>Séries : {ex.sets}</div>
                            <div>Répétitions : {ex.reps}</div>
                            <div>Tempo : {ex.tempo}</div>
                            <div>RIR : {ex.rir}</div>
                            <div>Repos : {ex.rest}</div>
                            {ex.group && <div>Groupe : {ex.group}</div>}
                            {ex.groupType && <div>Type : {ex.groupType}</div>}
                          </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <p style={{ color: "#888" }}>Aucun exercice trouvé.</p>
                  )}

                  {session.finisher && (
                    <div style={{ marginTop: 12, color: "#9fd" }}>
                      Finisher : {session.finisher}
                    </div>
                  )}
                </div>
              ))}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
